export const getVisualStyleList = () =>
    VISUAL_STYLE_TEMPLATES.map(({ content, ...meta }) => meta);

export const getVisualStyleById = (id: string): VisualStyleTemplate | undefined =>
    VISUAL_STYLE_TEMPLATES.find(t => t.id === id);